import{_ as a,o as e,c as r,a2 as d}from"./chunks/framework.DIMps2S2.js";const c=JSON.parse('{"title":"行情套餐","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"market-data/data-plans.md","filePath":"zh-CN/market-data/data-plans.md"}'),l={name:"market-data/data-plans.md"};function i(o,t,h,n,s,b){return e(),r("div",null,[...t[0]||(t[0]=[d('<h1 id="行情套餐" tabindex="-1">行情套餐 <a class="header-anchor" href="#行情套餐" aria-label="Permalink to &quot;行情套餐&quot;">​</a></h1><p>行情商店提供美股、港股、新加坡等市场的实时行情套餐订阅，本页说明套餐种类、订阅入口、权限规则及延迟行情限制。</p><h2 id="订阅入口" tabindex="-1">订阅入口 <a class="header-anchor" href="#订阅入口" aria-label="Permalink to &quot;订阅入口&quot;">​</a></h2><p>「我的」→「行情商店」</p><h2 id="可订阅套餐" tabindex="-1">可订阅套餐 <a class="header-anchor" href="#可订阅套餐" aria-label="Permalink to &quot;可订阅套餐&quot;">​</a></h2><h3 id="美股行情" tabindex="-1">美股行情 <a class="header-anchor" href="#美股行情" aria-label="Permalink to &quot;美股行情&quot;">​</a></h3><table tabindex="0"><thead><tr><th>产品名称</th><th>说明</th><th>起售价格</th></tr></thead><tbody><tr><td>全美综合行情</td><td>覆盖全美 16 家主流交易所及 FINRA TRF 场外数据的综合成交行情和最优买卖一档报价</td><td>32 HKD/月起</td></tr><tr><td>OPRA 美股期权行情</td><td>OPRA 美股期权实时成交行情及最优买卖一档报价</td><td>16 HKD/月起</td></tr><tr><td>美股深度摆盘</td><td>提供 60 档买卖盘报价，覆盖盘前、盘中、盘后及夜盘交易时段</td><td>130 HKD/月起</td></tr><tr><td>LV1 实时行情（OpenAPI）</td><td>纳斯达克实时成交行情及最优买卖一档报价（含夜盘），适用于 OpenAPI</td><td>333 HKD/月起</td></tr><tr><td>OPRA 美股期权行情（OpenAPI）</td><td>OPRA 美股期权实时成交行情，适用于 OpenAPI</td><td>16 HKD/月起</td></tr></tbody></table><h3 id="港股行情" tabindex="-1">港股行情 <a class="header-anchor" href="#港股行情" aria-label="Permalink to &quot;港股行情&quot;">​</a></h3><table tabindex="0"><thead><tr><th>产品名称</th><th>说明</th></tr></thead><tbody><tr><td>LV2 高级行情 Plus</td><td>港交所股票实时十档买卖盘报价，适用于移动端和桌面端</td></tr><tr><td>LV2 高级行情 Plus（OpenAPI）</td><td>港交所股票实时十档买卖盘报价，适用于 OpenAPI</td></tr></tbody></table><blockquote><p>部分行情产品（如港股 LV2 行情）受地域限制，仅支持在特定地区使用，购买前请确认是否符合使用条件。</p></blockquote><h3 id="新加坡行情" tabindex="-1">新加坡行情 <a class="header-anchor" href="#新加坡行情" aria-label="Permalink to &quot;新加坡行情&quot;">​</a></h3><p><strong>LV1 实时行情</strong>：新加坡股票实时成交行情及一档买卖盘报价</p><h2 id="优惠条件" tabindex="-1">优惠条件 <a class="header-anchor" href="#优惠条件" aria-label="Permalink to &quot;优惠条件&quot;">​</a></h2><ul><li><strong>美股</strong>：近 30 天美股成功交易次数 ≥ 2 次，账户总资产 ≥ 10,000 USD（或等值港币），可在兑换商城内使用任务币兑换全美综合行情。</li><li><strong>港股</strong>：开户后赠送港股 LV2 实时行情（仅限使用大陆网络用户）。</li><li><strong>新加坡</strong>：新加坡本地用户开户赠送 LV1 实时行情。</li></ul><h2 id="查看已订阅行情" tabindex="-1">查看已订阅行情 <a class="header-anchor" href="#查看已订阅行情" aria-label="Permalink to &quot;查看已订阅行情&quot;">​</a></h2><p>点击行情商店右上角「我的行情」，可查看当前账户行情权限状态（支持按全部 / 美股 / 港股 / 沪深 / 新加坡筛选）：</p><ul><li><strong>已开通行情</strong>：展示已订阅或推广期免费的权限，显示到期时间</li><li><strong>未开通行情</strong>：展示可购买的产品，点击跳转购买页</li></ul><h2 id="延迟行情" tabindex="-1">延迟行情 <a class="header-anchor" href="#延迟行情" aria-label="Permalink to &quot;延迟行情&quot;">​</a></h2><p>已开户未入金客户为延迟行情：</p><table tabindex="0"><thead><tr><th>市场</th><th>延迟说明</th></tr></thead><tbody><tr><td>港股</td><td>自选仅支持 20 只股票手动刷新实时行情，其余延迟 15 分钟，无盘口、经纪队列、异动数据</td></tr><tr><td>美股</td><td>OTC 股票延迟 15 分钟</td></tr></tbody></table><h2 id="单设备使用规则" tabindex="-1">单设备使用规则 <a class="header-anchor" href="#单设备使用规则" aria-label="Permalink to &quot;单设备使用规则&quot;">​</a></h2><p>应交易所要求，以下行情数据权限仅授权单一设备使用（移动端、桌面端、Web 端各计一台）。新设备登录后，原设备的高级行情权限会被自动抢占：</p><ul><li>港股 Level 1 行情</li><li>港股 Level 2 高级行情</li><li>美股 Level 1+ 全美高级行情</li><li>美股 OTC 市场实时行情</li><li>美股期权 Level 1 行情</li><li>美股深度摆盘 Nasdaq TotalView</li></ul><h2 id="权限抢占与恢复" tabindex="-1">权限抢占与恢复 <a class="header-anchor" href="#权限抢占与恢复" aria-label="Permalink to &quot;权限抢占与恢复&quot;">​</a></h2><p>原设备被抢占后会降为基础行情，页面显示提示与「重启行情」按钮。点击「重启行情」可恢复原设备的高级权限，同时另一设备降级。</p><h2 id="港股行情权限说明" tabindex="-1">港股行情权限说明 <a class="header-anchor" href="#港股行情权限说明" aria-label="Permalink to &quot;港股行情权限说明&quot;">​</a></h2><p>港股 LV1 实时行情的授权范围受审计规范调整，具体授权以 App 内显示为准。权限每次授权时长为 30 天，调整后用户会在 1–30 天内感知到变化。</p><h2 id="ios-收费说明" tabindex="-1">iOS 收费说明 <a class="header-anchor" href="#ios-收费说明" aria-label="Permalink to &quot;iOS 收费说明&quot;">​</a></h2><p>iOS 因平台抽成定价会比 Android 和电脑端略贵。</p><h2 id="引用此页面的文档" tabindex="-1">引用此页面的文档 <a class="header-anchor" href="#引用此页面的文档" aria-label="Permalink to &quot;引用此页面的文档&quot;">​</a></h2><ul><li><a href="/wiki/market-data">行情数据</a></li></ul>',31)])])}const p=a(l,[["render",i]]);export{c as __pageData,p as default};
